INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '_总论',
  '综合',
  '动静阴阳，反复迁变。虽万象之纷纭，须一理而融贯。
始以用神为第一要务，次看世应动变之消息。
月建为提纲，日辰为门户。用神有气无他伤，所谋遂意。
主象休囚遭克害，万事难成。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '求财',
  '求财',
  '财为养命之源，岂可忽诸。
妻财持世，利于求财。兄弟持世，破财之兆。
财爻旺相，生合世爻，求之必得。
财爻安静，须待冲开之日。
财爻被克，求之不易。
子孙发动，财源滚滚——子孙为财之原神，动则生财。
兄弟发动，劫夺之忧——兄弟为财之忌神，动则破财。
父母发动，辛劳求财——父母克子孙（原神），财路受阻。
官鬼发动，财来有灾——虽官鬼生父母而间接不利，更主因财致祸。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '事业',
  '事业',
  '官鬼为事业之主星。
官鬼持世，有职权在握之象。
官鬼生世，贵人提携。官鬼克世，小人倾轧或压力重重。
父母爻为文书印信，利于考试升迁。
妻财克父母，文书受阻。
子孙为官鬼之忌神——子孙持世或发动，不利求官。
世爻旺相，自身实力雄厚。世爻休囚，力不从心。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '感情',
  '感情',
  '感情之占，男以妻财为用，女以官鬼为用。
世爻为自己，应爻为对方。世应相生相合，两情相悦。
世应相冲相克，有缘无分或感情波折。
应爻空亡，对方无心。世爻空亡，自己犹豫。
桃花在世爻者，自身有魅力；桃花在应爻者，对方风流。
子孙持世，男占不利（克官鬼）；女占子孙为泄气之神。
兄弟持世，男占竞争多、破财；女占克夫之象。
六合卦主情投意合，六冲卦主有缘无分。
世应同动，两人皆主动；世应俱静，各怀心事。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '婚姻',
  '婚姻',
  '男占婚姻以妻财为用神，女占以官鬼为用神。
世应相生相合，婚姻可成。世应相冲相克，必有阻碍。
间爻动者，有媒人。应爻空亡，对方无心。
财官旺相，佳偶天成。财官休囚被克，婚事坎坷。
六冲变六合，先难后易。六合变六冲，先热后冷。
父母持世，婚迟；父母为婚书，动则有消息。
兄弟持世，男占不利（劫财克妻）。子孙持世，女占不利（克夫）。
世应相合带刑，婚后多争吵。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '考试',
  '考试',
  '考试功名以父母爻为用神（文书印信之象）。
父母持世旺相，考运亨通，金榜题名。
父母休囚或被克，成绩不理想。
官鬼为父母之原神——官鬼旺动生父母，有贵人提携。
妻财为父母之忌神——财爻发动克父母，心思不在学业。
子孙发动克官鬼，间接不利（泄父母之原神）。
世爻旺相，自身实力足够。世爻休囚，准备不充分。
应爻为考官或学校。应爻生世，被录取之象。应爻克世，未中。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '家宅',
  '家宅',
  '家宅之占以二爻为宅爻，父母爻为房屋。
父母旺相，房屋坚固。父母休囚，年久失修。
二爻安静不受克，家宅安宁。二爻动或被冲，家中不安。
官鬼为祸害之源——官动克世，家中有灾。
子孙持世，家宅平安（子孙克制官鬼）。
兄弟持世，破财之象。妻财持世，进财之兆。
青龙临父母，华屋美宅。白虎临官鬼，有伤病之忧。
世应相生，邻里和睦。世应相克，邻里不和。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '疾病',
  '疾病',
  '官鬼为病症之主星。
官鬼旺而克世，病重。官鬼休囚，病轻。
子孙持世或发动，克制官鬼，利于康复。
子孙为医药，旺则药到病除。
用神入墓，病情缠绵。用神化绝，生死攸关。
世爻空亡，如人之魂不守舍。
父母发动，忧虑操劳加重病情。
兄弟动，耗财求医。妻财动，有药费支出但利求医。
六冲卦，病来得快去得快。六合卦，病情缠绵。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '出行',
  '出行',
  '世爻为出行之人，应爻为目的地。
世爻旺相，利于出行。世爻休囚，出行不利。
子孙为出行之用神，旺则平安。
官鬼发动，途中有灾。
父母持世，车船劳顿（父母为车船之象）。
应爻生世，目的地有利于我。应爻克世，彼地不利。
世爻动，主动出行。世爻静，被动出行或不成行。
兄弟持世，花销大。妻财持世，有利可图。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '诉讼',
  '诉讼',
  '世为我方，应为对方。
世旺应衰，我胜。应旺世衰，我败。
官鬼持世，有理有势。官鬼克世，受官府压制。
父母为状纸文书。兄弟为争端之源。
世应俱空，两不相干，不了了之。
六合卦主和解，六冲卦主决裂。
子孙为解讼之神——子孙发动克官，官事消散。
妻财为理由——财旺则理由充分。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '失物',
  '失物',
  '失物之占以妻财为用神。
财爻旺相不空，失物可寻。财爻空亡入墓，难觅。
财在内卦，物在家中。财在外卦，物在外面。
财临初爻，在地面低处。临二爻，在宅内。临三爻，在门户附近。
临四爻，在远处。临五爻，在道路上。临六爻，在高处或远方。
世爻克财，自己能找到。应爻克财，他人拾去。
鬼爻发动，被人偷盗。鬼静财空，自己遗忘所放之处。
子孙发动，克鬼泄财——物已损坏或变质。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '天气',
  '天气',
  '天时之占：父母为雨，子孙为晴，妻财为风，官鬼为雷电雪霜，兄弟为云雾。
父母持世发动，有雨。子孙持世发动，天晴。
妻财发动，有风。官鬼发动，有雷电或异常天象。
兄弟动，多云或阴天。
水爻动，主雨。火爻动，主晴热。木爻动，主风。金爻动，主霜雪。土爻动，主阴云。
卦逢六冲，天气变化快。卦逢六合，天气持续稳定。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '怀孕',
  '怀孕',
  '六甲占以子孙爻为用神。
子孙旺相，胎儿健康。子孙休囚受克，须注意保胎。
子孙为阳爻，生男。子孙为阴爻，生女。
官鬼为产厄——官鬼旺动克世，生产有险。
父母为催生之神——父母动，产期近。
妻财为孕妇——财爻旺相，母体安泰。财爻休囚，孕妇体弱。
子孙入墓，胎气不顺。子孙化绝，有流产之忧。
世爻空亡，心绪不安。青龙临子孙，大吉之兆。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '投资',
  '投资',
  '投资之占与求财类似，以妻财为用神，但更重动变消息。
财爻旺动生世，投资获利。财爻休囚化退，亏损之象。
子孙为财之原神——子孙旺动，投资标的向好。
兄弟为劫财之神——兄弟动，有人争利或庄家收割。
官鬼为风险——官鬼暗动或明动，投资有政策风险或黑天鹅。
世爻化进神，越投越旺。世爻化退神，宜及时止损。
六冲卦，市场震荡大。六合卦，走势平稳。
财化财（化比和），获利持平。财化兄（化忌），先赚后亏。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '求职',
  '求职',
  '求职以官鬼为用神（官鬼为职位之象）。
官鬼持世或生世，求职顺利。官鬼克世，面试受挫。
官鬼空亡，无职位空缺。官鬼旺相，职位好。
父母为单位、文书——父母生世，单位看重自己。
应爻为用人单位。应爻生世，公司需要你。应爻克世，不录用。
世应相合，双方满意。世应相冲，谈不拢。
兄弟持世，竞争者多。子孙持世，不利求职（子孙克官）。
妻财持世，因财求职或薪资理想。',
  datetime('now'),
  datetime('now')
);

INSERT OR REPLACE INTO huangjince (category, label, text, created_at, updated_at) VALUES (
  '生意',
  '生意',
  '生意合伙以妻财为用神，兼看世应关系。
世为自己，应为合伙人或客户。世应相生，合作愉快。
世应相克，合伙生隙。世应相合，同心同德。
妻财旺相，生意兴隆。妻财休囚，经营困难。
子孙为利润之源——子孙旺动，客源充足。
兄弟为竞争——兄弟持世或动，同行竞争大或合伙人争利。
官鬼为经营风险——官鬼旺动，有政策限制或法律纠纷。
父母为合同文书——父母旺相，合同有保障。父母空亡，口头承诺不可靠。',
  datetime('now'),
  datetime('now')
);

